// NestJS 모놀리스 초기화: apps/server(NestJS) + apps/web(React+Vite)
init nest app (AuthModule, UserModule, RoleModule, DocumentModule, AuditModule)
init prisma (datasource = PostgreSQL)

// 단일 진실원 스키마 — 도메인 불변 반영
model User        { id, email(unique), passwordHash, dept, grade, status }
model Role        { id, name, permissions Permission[] }            // 관리자/부서장/일반사원/조회전용
model Permission  { id, code, (read|write|delete|approve) }
model UserRole    { userId, roleId }  // N:M 매핑
model Document    { id, ownerId, classification, tags[], body, accessPolicy(jsonb) }
model AuditLog    { id, actorId, ts, action, targetType, targetId, before(jsonb), after(jsonb) }

// append-only 불변 강제 (web-audit-log)
add pg constraint: REVOKE UPDATE, DELETE ON AuditLog FROM app_role
add trigger: block any UPDATE/DELETE on AuditLog → raise exception

prisma migrate dev --name init_schema
// 마이그레이션은 선형/재현 가능 (prisma why → 단일 진실원)

// 권한 부여/회수 UI 없이 출시 금지 → 코어 인가를 먼저 확립
PermissionsGuard(permissions: string[]):
  canActivate(req):
    user = req.user
    perms = user.roles.flatMap(r -> r.permissions.map(p -> p.code))
    if !subset(permissions, perms): throw Forbidden
    return true

// 문서 접근 정책: 부서/직급/역할 기반
docAccessPolicy(user, doc, action):
  if action in [write,delete,approve] && !hasPerm(action): deny
  if user.dept == doc.accessPolicy.dept OR user.grade >= doc.accessPolicy.minGrade
     OR doc.ownerId == user.id: allow
  else deny

// 데코레이터로 라우트 단위 인가 강제
@Get('documents/:id') @UseGuards(JwtAuthGuard, PermissionsGuard(['read']))
@Delete('documents/:id') @Permissions(['delete'])

// 모든 외부 입력을 Zod로 서버 검증 — 클라이언트 검증은 UX 보조일 뿐
const CreateDocSchema = z.object({
  title:   z.string().min(1).max(200),
  body:    z.string().max(50000),
  class:   z.enum(['public','internal','confidential']),  // 허용 범위(화이트리스트)
  tags:    z.array(z.string().regex(/^[a-z0-9-]+$/)).max(20),
})

ZodValidationPipe(schema):
  transform(value): parsed = schema.parse(value)   // 실패 → 400, 원시값 신뢰 금지
    stripUnknownKeys(parsed)                        // 대량 할당(mass assignment) 차단

@Post('documents') @UsePipes(new ZodValidationPipe(CreateDocSchema))
// 업로드 파일 메타·검색 질의·API 파라미터도 각각 전용 Zod 스키마 적용
searchQuerySchema = z.object({ q: z.string().max(100), page: z.coerce.number().int().min(1) })

// 민감 변경: 권한변경/부여회수/문서삭제/승인결재
@Audit('PERMISSION_GRANTED')  // 인터셉터/데코레이터
writeAudit(actor, action, target, before, after):
  prisma.auditLog.create({ actorId:actor.id, ts:now, action, targetType, targetId, before, after })
  // UPDATE/DELETE는 DB 트리거 + 권한 REVOKE로 물리적 append-only 보장(Phase 1)
  // 감사 기록은 본 변경과 동일 트랜잭션 → 원자성

AuditInterceptor:
  capture beforeSnapshot (pre-handler)
  run handler
  capture afterSnapshot (post-handler)
  if action in SENSITIVE_ACTIONS: appendAudit(before, after)
// 운영자·문서 라우트에 @UseInterceptors(AuditInterceptor) 적용

// 외부 인프라 없이 PG 내장 FTS; 질의는 파라미터화 + 화이트리스트 검증
DocumentService.search(user, query):
  q = sanitizeSearchQuery(query.q)          // Zod 검증 + 위험 토큰 제거
  tsq = to_tsquery(q)                       // 파라미터화 (SQL 인젝션 방지)
  // 권한 필터를 DB 계층에서 강제 — 권한 필터 우회 방지
  rows = prisma.$queryRaw`
    SELECT d.*, ts_rank_cd(tsv, ${tsq}) rank
    FROM document d
    WHERE tsv @@ ${tsq}
      AND (${user.dept} = ANY(d.access_dept) OR d.owner_id = ${user.id})
      AND NOT d.deleted
    ORDER BY rank DESC LIMIT 50`
  return rows   // 검색 결과도 접근 제어 통과
// 인덱스: CREATE INDEX doc_tsv ON document USING GIN(to_tsvector(...))
// 확장 경로: 인터페이스(SearchEngine) 분리 → Meilisearch/Elasticsearch로 교체 가능

// 역할 할당/회수, 사용자 권한 부여/철회 — 필수
AdminController @UseGuards(JwtAuthGuard, PermissionsGuard(['manage_users'])):
  assignRole(admin, userId, roleId):
    before = loadUserRoles(userId)
    $tx(prisma.userRole.create({userId,roleId});
         writeAudit(admin,'ROLE_ASSIGNED',userId,before,after))
  revokeRole(admin, userId, roleId):
    $tx(prisma.userRole.delete(...); writeAudit(admin,'ROLE_REVOKED',...))
  grantPermission(admin, roleId, permCode):   // 동일 패턴 + 감사
  revokePermission(admin, roleId, permCode)
  listAuditLogs(filter): return append-only 스트림(읽기 전용)

